var rrwebRecord = rrweb.record;


function lengthInUtf8Bytes(str) {
  var m = encodeURIComponent(str).match(/%[89ABab]/g);
  return str.length + (m ? m.length : 0);
}

function generateRandomId() {
  return [...Array(40)].map(() => Math.random().toString(36)[2]).join('');
}

const LOGS_ENABLED = false;
function log(...args) {
  if (LOGS_ENABLED) {
    console.log(...args);
  }
}

const POST_URL = new URL("./events", document.currentScript.src).href;
const POST_INTERVAL_SECONDS = 15;
const KEEPALIVE_BYTE_LIMIT = 60000; // Fetch payloads >64kb cannot use keepalive: true
const RECORDING_TAG_SELECTOR = 'meta[name="spectator-sport-recording-tag"]';
const RECORDING_LABEL_SELECTOR = 'meta[name="spectator-sport-recording-label"]';
const STOP_SELECTOR = 'meta[name="spectator-sport-stop"]';

function getSessionId() {
  const STORAGE_NAME = "spectator_sport_session_id";
  let id = window.localStorage.getItem(STORAGE_NAME);
  if (!id) {
    id = generateRandomId();
    window.localStorage.setItem(STORAGE_NAME, id);
  }
  return id;
}

function getWindowId() {
  const STORAGE_NAME = "spectator_sport_window_id";
  let id = window.sessionStorage.getItem(STORAGE_NAME);
  if (!id) {
    id = generateRandomId();
    window.sessionStorage.setItem(STORAGE_NAME, id);
  }
  return id;
}

class Recorder {
  constructor(sessionId, windowId) {
    this.sessionId = sessionId;
    this.windowId = windowId;

    this.events = new Events(sessionId, windowId);

    this.stopRrwebCallback = null; // rrweb's stop function
  }

  start() {
    if (!this.stopRrwebCallback) {
      this.stopRrwebCallback = rrwebRecord({
        emit: this.events.add.bind(this.events),
      });
    }

    this.events.startFlushing();
  }

  stop() {
    this.events.stopFlushing();

    if (this.stopRrwebCallback) {
      this.stopRrwebCallback();
      this.stopRrwebCallback = null;
    }

    this.events.transmit(true);
  }

  pause() {
    this.events.stopFlushing();
    this.events.transmit(true);
  }

  unpause() {
    this.start();
  }
}

class Events {
  constructor(sessionId, windowId) {
    this.sessionId = sessionId;
    this.windowId = windowId;

    this.events = [];
    this.eventBytes = 0;
    this.flushIntervalId = null;
  }

  startFlushing() {
    if (!this.flushIntervalId) {
      this.flushIntervalId = setInterval(() => {
        this.transmit(false);
      }, POST_INTERVAL_SECONDS * 1000);
    }
  }

  stopFlushing() {
    if (this.flushIntervalId) {
      clearInterval(this.flushIntervalId);
      this.flushIntervalId = null;
    }
  }

  add(event) {
    const serializedEvent = JSON.stringify(event);
    const newEventBytes = lengthInUtf8Bytes(serializedEvent);

    this.events.push(event);
    this.eventBytes = this.eventBytes + newEventBytes;

    if (this.eventBytes > KEEPALIVE_BYTE_LIMIT) {
      this.events.push(event);
      this.debouncedTransmit();
    }
  }

  transmit(keepalive = false) {
    if (this.events.length === 0) {
      return
    }

    const body = JSON.stringify({
      sessionId: this.sessionId,
      windowId: this.windowId,
      events: this.events
    });

    this.events.length = 0;
    this.eventBytes = 0;

    fetch(POST_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      keepalive: keepalive,
      body,
    }).catch((error) => {
      console.error(error);
    });
  }

  debouncedTransmit() {
    if (!this.debouncedTransmitTimeout) {
      this.debouncedTransmitTimeout = setTimeout(function() {
        this.transmit(false);
      }.bind(this), 100);
    }

  }
}

class TagWatcher {
  constructor(sessionId, windowId) {
    this.sessionId = sessionId;
    this.windowId = windowId;
    this.seenTags = new Set();
    this.pendingTags = [];
    this.debounceTimeout = null;
    this.observer = null;
  }

  start() {
    document.querySelectorAll(RECORDING_TAG_SELECTOR).forEach(el => {
      this.enqueue(el.content);
    });

    this.observer = new MutationObserver((mutations) => {
      for (const mutation of mutations) {
        for (const node of mutation.addedNodes) {
          if (node.nodeType !== Node.ELEMENT_NODE) continue;
          if (node.matches(RECORDING_TAG_SELECTOR)) {
            this.enqueue(node.content);
          }
          node.querySelectorAll(RECORDING_TAG_SELECTOR).forEach(el => {
            this.enqueue(el.content);
          });
        }
      }
    });
    this.observer.observe(document.documentElement, { childList: true, subtree: true });
  }

  enqueue(signedTag) {
    if (this.seenTags.has(signedTag)) return;
    this.seenTags.add(signedTag);
    this.pendingTags.push(signedTag);
    this.debouncedFlush();
  }

  debouncedFlush() {
    if (!this.debounceTimeout) {
      this.debounceTimeout = setTimeout(() => {
        this.debounceTimeout = null;
        this.flush();
      }, 100);
    }
  }

  flush() {
    if (this.pendingTags.length === 0) return;
    const tags = this.pendingTags.splice(0);
    fetch(POST_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sessionId: this.sessionId, windowId: this.windowId, events: [], tags }),
    }).catch((error) => {
      console.error(error);
    });
  }
}

